    }
    )
    }



    @Throws(ProllyBindingException::class)override fun `exactPage`(`term`: kotlin.ByteArray, `cursor`: kotlin.ByteArray?, `limit`: kotlin.ULong): IndexPageRecord {
            return FfiConverterTypeIndexPageRecord.lift(
