        override fun callback(`uniffiHandle`: Long,`primaryKey`: RustBuffer.ByValue,`sourceValue`: RustBuffer.ByValue,`uniffiOutReturn`: RustBuffer,uniffiCallStatus: UniffiRustCallStatus,) {
